__attribute__((used, noinline))
static void init_mixed_region_pool(void) {
    if (CONFIG_MIXED_REGION_NODE_COUNT == 0) {
        g_mixed_region_cursor = 0;
        return;
    }
    for (uint32_t idx = 0; idx < CONFIG_MIXED_REGION_NODE_COUNT; ++idx) {
        uint32_t cur = kMixedRegionOffsets[idx];
        uint32_t nxt = kMixedRegionOffsets[(idx + 1) % CONFIG_MIXED_REGION_NODE_COUNT];
        *(uintptr_t *)(g_mixed_region_pool + cur) = (uintptr_t)(g_mixed_region_pool + nxt);
    }
    g_mixed_region_cursor = (uintptr_t)(g_mixed_region_pool + kMixedRegionOffsets[0]);
}

