    if (!allocate_memory_region((void **)&g_data_pointer_chase_pool, (uint64_t)(CONFIG_DATA_POINTER_CHASE_POOL_BYTES), 4096u, "data_pointer_chase")) return 2;
    if (!allocate_memory_region((void **)&g_data_page_stride_buf, (uint64_t)(CONFIG_DATA_PAGE_STRIDE_POOL_BYTES), 4096u, "data_page_stride")) return 2;
    if (!allocate_memory_region((void **)&g_data_indirect_gather_pool, (uint64_t)(CONFIG_DATA_INDIRECT_GATHER_POOL_BYTES), 4096u, "data_indirect_gather")) return 2;
