    if (!allocate_memory_region((void **)&g_data_cold_stride_buf, (uint64_t)(CONFIG_DATA_COLD_STRIDE_BUFFER_BYTES), 4096u, "data_cold_stride")) return 2;
    if (!allocate_memory_region((void **)&g_data_tlb_indirect_buf, (uint64_t)(CONFIG_DATA_TLB_INDIRECT_POOL_BYTES), 4096u, "data_tlb_indirect")) return 2;
    if (!allocate_memory_region((void **)&g_hot_l1_attached_pool, (uint64_t)(CONFIG_HOT_L1_ATTACHED_POOL_BYTES), 4096u, "hot_region_loop")) return 2;
    if (!allocate_memory_region((void **)&g_itlb_attached_pool, (uint64_t)(CONFIG_ITLB_ATTACHED_POOL_BYTES), 4096u, "itlb")) return 2;
    if (!allocate_memory_region((void **)&g_mixed_region_pool, (uint64_t)(CONFIG_MIXED_REGION_POOL_BYTES), 4096u, "mixed_region_loop")) return 2;
    if (!allocate_memory_region((void **)&g_mixed_region_1_pool, (uint64_t)(CONFIG_MIXED_REGION_1_POOL_BYTES), 4096u, "mixed_region_loop_1")) return 2;
    if (!allocate_memory_region((void **)&g_mixed_region_2_pool, (uint64_t)(CONFIG_MIXED_REGION_2_POOL_BYTES), 4096u, "mixed_region_loop_2")) return 2;
    if (!allocate_memory_region((void **)&g_mixed_region_3_pool, (uint64_t)(CONFIG_MIXED_REGION_3_POOL_BYTES), 4096u, "mixed_region_loop_3")) return 2;
    if (!allocate_memory_region((void **)&g_mixed_region_4_pool, (uint64_t)(CONFIG_MIXED_REGION_4_POOL_BYTES), 4096u, "mixed_region_loop_4")) return 2;
